class Solution:
    def checkSubarraySum(self, nums, k):
        first = {0: -1}
        run = 0
        for i, v in enumerate(nums):
            run = (run + v) % k
            if run in first:
                if i - first[run] >= 2:
                    return True
            else:
                first[run] = i
        return False

