var checkSubarraySum = function(nums, k) {
    const first = new Map();
    first.set(0, -1);
    let run = 0;
    for (let i = 0; i < nums.length; i++) {
        run = (run + nums[i]) % k;
        if (first.has(run)) {
            if (i - first.get(run) >= 2) return true;
        } else {
            first.set(run, i);
        }
    }
    return false;
};
